import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as i,f as l}from"./app-d9d82146.js";const c={},d=l('<p>package.json</p><h3 id="必须属性" tabindex="-1"><a class="header-anchor" href="#必须属性" aria-hidden="true">#</a> 必须属性</h3><ol><li>name: 项目名字，不能重复。</li><li>version：项目的版本号，每次项目改动后，即将发布时，需要手动改项目的版本号。每个版本号由三个部分组成：主版本号.次版本号.修订号。 <ul><li>修订号(bug)、次版本号（新增了功能和特性）、主版本号（新版本无法兼容基于前一版本的代码）</li><li>^ 兼容某个大版本，下载的包可能会是更高的次版本号或者修订版本号，如：^1.1.2，可以是1.1.n、1.2.n</li><li><sub>兼容某个次版本，下载的包可能会是更高的修订版本号,如：</sub>1.1.2，可以是1.1.2、1.1.n</li></ul></li></ol><h3 id="描述信息" tabindex="-1"><a class="header-anchor" href="#描述信息" aria-hidden="true">#</a> 描述信息</h3><ol><li>description：描述项目包，方便在npm搜索可以找到这个包</li><li>author：包作者 contributors：包贡献者</li><li>homepage：项目主页，官网地址文档等</li><li>repository：仓库地址</li></ol><h3 id="依赖配置" tabindex="-1"><a class="header-anchor" href="#依赖配置" aria-hidden="true">#</a> 依赖配置</h3><ol><li>生产依赖<code>dependencies</code><ul><li>项目运行时所依赖的模块,在生产环境中要用到的，当你使用第三方包时候，会同步下载第三方包的<code>dependencies</code></li></ul></li><li>开发依赖<code>devDependencies</code><ul><li>项目开发所需要的模块，项目运行的时候又用不到的，如<code>webpack、eslint、预处理器、测试工具</code>等，</li></ul></li><li>同版本的依赖<code>peerDependencies </code><ul><li>在很多第三方包都有应用的，如vuex依赖的第三方包是vue，这时候它会在<code>peerDependencies</code>中声明，和主项目共用同一个vue依赖，避免了重复安装。</li></ul></li></ol><h3 id="脚本配置" tabindex="-1"><a class="header-anchor" href="#脚本配置" aria-hidden="true">#</a> 脚本配置</h3><ol><li>scripts：用于定义脚本命令，供npm直接调用</li><li>config：来配置scripts运行时的配置参数</li></ol><h3 id="文件与目录" tabindex="-1"><a class="header-anchor" href="#文件与目录" aria-hidden="true">#</a> 文件与目录</h3><ol><li>入口文件，main、brower、module都是用于指定js的入口文件路径，他们的作用是帮助不用的环境如node或浏览器找到正确的文件入口。 <ul><li><code>main</code>--通用commonjs入口 <ul><li>指定加载的入口文件，在browser和Node环境中都可以使用，当通过require引用包时，会查找 main 字段指定的文件。文件格式是.js文件，<code>&quot;main&quot;: &quot;./lib/index.js&quot;</code></li><li>通常指向一个CommonJS格式（require/exports）的文件。当用户运行<code>const pkg = require(&#39;your-package&#39;)</code>时，实际加载的是<code>./lib/index.js</code></li></ul></li><li><code>brower</code>--浏览器专用入口 <ul><li>定义npm包在browser环境下的入口文件，主要适用于专门为浏览器提供特定的代码，如某些包使用浏览器专有的语法。格式为.js,<code>&quot;browser&quot;: &quot;./lib/browser.js&quot;</code></li><li>适宜严禁在server端使用的npm包</li></ul></li><li><code>module</code>--ES Modules 入口 <ul><li>定义npm包的ESM规范的入口文件，指向 <code>ES Modules（import/export）</code>格式的文件。</li><li>主要使用于js模块化的打包工具<code>（Rollup、Webpack5）</code>,Webpack、Rollup 等工具优先使用此字段，以启用<code>Tree Shaking</code>优化。</li><li>文件格式通常是<code>.mjs .js</code>,<code>&quot;module&quot;: &quot;./lib/index.mjs&quot;</code> <code>&quot;main&quot;: &quot;./lib/index.cjs&quot;</code>,</li></ul></li></ul></li><li>bin <ul><li>指定各个内部命令对应的可执行文件的位置，所有<code>node_modules/.bin /</code>目录下的命令，都可以用 npm run [命令] 的格式运行。</li><li><code>&quot;bin&quot;: { &quot;someTool&quot;: &quot;./bin/someTool.js&quot; }</code>,定义了一个命令<code>someTool</code>，它对应的可执行文件的位置是<code>./bin/someTool.js</code>，这样我们就能在scripts里面直接使用该命令了someTool</li></ul></li><li>files:是一个数组，用来描述当把 npm 包作为依赖包安装时需要说明的文件列表。当 npm 包发布时，files 指定的文件会被推送到 npm 服务器中，定义在files的文件，是会让用户看到的文件。规定哪些文件会被用户所下载。</li></ol><h3 id="发布配置" tabindex="-1"><a class="header-anchor" href="#发布配置" aria-hidden="true">#</a> 发布配置</h3><ol><li>private：字段可以防止我们意外地将私有库发布到npm服务器</li><li>os：os字段可以让我们设置该npm包可以在什么操作系统使用</li><li>cpu</li><li>license：字段用于指定软件的开源协议，开源协议表述了其他人获得代码后拥有的权利</li></ol><h3 id="第三方配置" tabindex="-1"><a class="header-anchor" href="#第三方配置" aria-hidden="true">#</a> 第三方配置</h3><ol><li>eslintConfig：eslint的配置可以写在单独的配置文件<code>.eslintrc.json </code>中，也可以写在<code>package.json</code>文件的<code>eslintConfig</code>配置项中</li><li>babel：babel的配置可以写在单独的配置文件<code>babel.config.json </code>中，也可以写在<code>package.json</code>文件的<code>babel</code>配置项中</li><li>lint-staged：一个在Git暂存文件上运行<code>linters</code>的工具，通常配合<code>gitHooks</code>一起使用，使用<code>lint-staged</code>时，每次提交代码只会检查当前改动的文件</li><li>gitHooks：来定义一个钩子，比如在提交（commit）之前执行<code>lint-staged</code></li><li>browserslist：用来告知支持哪些浏览器及版本</li></ol><h3 id="package-lock-json" tabindex="-1"><a class="header-anchor" href="#package-lock-json" aria-hidden="true">#</a> package-lock.json</h3><ol><li><code>package-lock.json</code>文件的目的是用来锁定包版本的，为了保证在任意的机器上我们去执行<code>npm install</code>都会得到完全相同的<code>node_modules</code>安装结果，所以lock文件需要一起提交到仓库中去。</li><li><code>package-lock.json</code>它会在npm更改<code>node_modules</code>目录树或者<code>package.json</code>时自动生成的, 它准确的描述了当前项目npm包的依赖树</li><li>一般升级包：执行<code>npm install @..</code> 命令后，验证没有问题之后, 是需要提交新的<code>package.json</code>和<code>package-lock.json</code>文件</li></ol>',17),a=[d];function n(s,r){return o(),i("div",null,a)}const p=e(c,[["render",n],["__file","包发布以及package.json.html.vue"]]);export{p as default};
